// --- Sparse-CBOR write (ADR-0042 driver path). ---

// Marshal writes the SoA buffer to w as the sparse-CBOR wire
// format produced through factsschema/dml_cbor. Thin wrapper
// around M1SampleBuildEntities — the per-row chain lives there and
// works against any leeway-DML class that structurally satisfies
// M1SampleEntityI.
func (c *M1SampleColumns) Marshal(w io.Writer) (err error) {
	ent := m1SamplePool.Get().(*cbdml.InEntityFacts)
	defer m1SamplePool.Put(ent)
	ent.SetActiveSections(M1SampleActiveSections)
	ent.Builder().SetActiveFields(M1SampleActiveFields())
	err = M1SampleBuildEntities(ent, c)
	if err != nil {
		return
	}
	var recs []*arrowrowcbor.Record
	recs, err = ent.TransferRecords(nil)
	if err != nil {
		err = eh.Errorf("m1fixture: transfer records: %w", err)
		return
	}
	rb := arrowrowcbor.JoinRecords(recs)
	_, err = w.Write(rb)
	if err != nil {
		err = eh.Errorf("m1fixture: marshal write: %w", err)
	}
	return
}

