// Unmarshal appends one row to c per entity in rec, projecting
// the runtime.facts columns through factsschema/ra. Thin wrapper
// around M1SampleFillFromArrow — the per-row decode lives there.
func (c *M1SampleColumns) Unmarshal(rec arrow.Record) (err error) {
	r := newM1SampleReader()
	defer r.release()
	err = r.loadFromRecord(rec)
	if err != nil {
		return
	}
	n := r.EntityId.Len()
	err = M1SampleFillFromArrow(
		c,
		n,
		r.EntityId.ValueId,
		r.EntityId.ValueNaturalKey,
		r.EntityTimestamp.ValueTs,
		r.Symbol.Attributes, r.Symbol.Memberships,
		r.U8Array.Attributes, r.U8Array.Memberships,
		r.U16Array.Attributes, r.U16Array.Memberships,
		r.U32Array.Attributes, r.U32Array.Memberships,
		r.U64Array.Attributes, r.U64Array.Memberships,
		r.F32Array.Attributes, r.F32Array.Memberships,
		r.F64Array.Attributes, r.F64Array.Memberships,
		r.Bool.Attributes, r.Bool.Memberships,
		r.BlobArray.Attributes, r.BlobArray.Memberships,
		r.TimeArray.Attributes, r.TimeArray.Memberships,
		r.StringArray.Attributes, r.StringArray.Memberships,
		r.TextArray.Attributes, r.TextArray.Memberships,
	)
	return
}

// --- buscodec.CodecI bridge. ---

// M1SampleCodec is the buscodec.CodecI bridge for M1Sample. Encodes one row
// through dml_cbor; decodes via cborarrow.Convert + ra-Unmarshal +
// Row(0). Auto-registered in init() so callers using buscodec.Encode
// / Decode route through here instead of the CBOR fallback.
type M1SampleCodec struct{}

var _ buscodec.CodecI = (*M1SampleCodec)(nil)

// m1SampleBusCodec is the package-local singleton wired into buscodec.
var m1SampleBusCodec = &M1SampleCodec{}

func (inst *M1SampleCodec) Name() (n string) {
	n = "m1Sample-sparse-cbor"
	return
}

func (inst *M1SampleCodec) ContentType() (ct string) {
	ct = "application/x-runtime-facts+rb;kind=m1Sample"
	return
}

func (inst *M1SampleCodec) Encode(v any) (b []byte, err error) {
	var row M1Sample
	switch x := v.(type) {
	case M1Sample:
		row = x
	case *M1Sample:
		if x == nil {
			err = eh.Errorf("m1fixture: Encode nil *M1Sample")
			return
		}
		row = *x
	default:
		err = eh.Errorf("m1fixture: Encode requires M1Sample or *M1Sample, got %T", v)
		return
	}
	cols := &M1SampleColumns{}
	cols.Append(row)
	var buf bytes.Buffer
	err = cols.Marshal(&buf)
	if err != nil {
		err = eh.Errorf("m1fixture: Encode marshal: %w", err)
		return
	}
	b = buf.Bytes()
	return
}

func (inst *M1SampleCodec) Decode(b []byte, v any) (err error) {
	target, ok := v.(*M1Sample)
	if !ok {
		err = eh.Errorf("m1fixture: Decode requires *M1Sample, got %T", v)
		return
	}
	var arrowBuf bytes.Buffer
	err = cborarrow.Convert(bytes.NewReader(b), &arrowBuf)
	if err != nil {
		err = eh.Errorf("m1fixture: Decode cborarrow: %w", err)
		return
	}
	rd, err := ipc.NewReader(&arrowBuf)
	if err != nil {
		err = eh.Errorf("m1fixture: Decode ipc reader: %w", err)
		return
	}
	defer rd.Release()
	if !rd.Next() {
		err = eh.Errorf("m1fixture: Decode expected one Arrow record, got none")
		return
	}
	rec := rd.RecordBatch()
	defer rec.Release()
	cols := &M1SampleColumns{}
	err = cols.Unmarshal(rec)
	if err != nil {
		err = eh.Errorf("m1fixture: Decode unmarshal: %w", err)
		return
	}
	if cols.Len() != 1 {
		err = eb.Build().Int("got", cols.Len()).Errorf("m1fixture: Decode expected 1 row")
		return
	}
	*target = cols.Row(0)
	return
}
